svg.script:

// State Configuration
let currentView = 'airfoil';

// Physics Variables
let state = {
    'rpm': 40,    // 0 to 100
    'pitch': 10   // 0 to 20
};

// Animation States
let lastTime = 0;
let windOffset = 0;
let spinAngle = 0;

// Slider Configurations
const SLIDER_WIDTH = 350;
let activeSlider = null;

const sliderConfig = {
    'rpm': { min: 0, max: 100 },
    'pitch': { min: 0, max: 20 }
};

// View Data
const viewData = {
    'airfoil': {
        color: '#3b82f6',
        title: 'The Rotor Blade as an Airfoil',
        desc: 'A rotor blade is fundamentally just a long, thin airplane wing (an airfoil). As relative wind strikes the leading edge, the blade\'s angled Pitch (Angle of Attack) forces air downward. By Newton\'s Third Law and Bernoulli\'s principle, this creates an upward force called <strong>Lift</strong>.'
    },
    'spin': {
        color: '#8b5cf6',
        title: 'Why Spinning Matters (Relative Wind)',
        desc: 'Fixed-wing airplanes must move their entire body forward to push air over their wings. Helicopters <strong>spin</strong> their wings instead! Spinning creates "Relative Wind" over the blades even when the helicopter is standing still. Notice how the blade tips travel much faster than the root.'
    }
};

function initSimulation() {
    setView('airfoil');
    updateVisuals();
    requestAnimationFrame(animationLoop);
}

// View Selection
function setView(viewId) {
    currentView = viewId;
    const data = viewData[viewId];

    // Update Tabs
    document.querySelectorAll('.tab').forEach(el => el.classList.remove('active'));
    document.getElementById('tab-' + viewId).classList.add('active');

    // Toggle SVG Groups
    document.getElementById('view-airfoil').setAttribute('display', viewId === 'airfoil' ? 'block' : 'none');
    document.getElementById('view-spin').setAttribute('display', viewId === 'spin' ? 'block' : 'none');

    // Update Info Panel
    document.getElementById('info-badge').style.backgroundColor = data.color;
    document.getElementById('info-title').textContent = data.title;
    document.getElementById('info-desc').innerHTML = data.desc;
}

// Drag Handling
function startDrag(evt, id) {
    activeSlider = id;
    updateDrag(evt);
}

function onMouseMove(evt) {
    if (activeSlider) {
        updateDrag(evt);
    }
}

function onMouseUp(evt) {
    activeSlider = null;
}

function updateDrag(evt) {
    const svg = document.getElementById('aero-svg');
    const pt = svg.createSVGPoint();
    pt.x = evt.clientX;
    pt.y = evt.clientY;
    const svgP = pt.matrixTransform(svg.getScreenCTM().inverse());

    // Sliders track starts at x=770
    let localX = svgP.x - 770;
    if (localX < 0) localX = 0;
    if (localX > SLIDER_WIDTH) localX = SLIDER_WIDTH;

    const conf = sliderConfig[activeSlider];
    state[activeSlider] = conf.min + (localX / SLIDER_WIDTH) * (conf.max - conf.min);

    // Update Slider Visuals
    document.getElementById('track-' + activeSlider).setAttribute('x2', localX);
    document.getElementById('thumb-' + activeSlider).setAttribute('cx', localX);

    let valSuffix = activeSlider === 'rpm' ? '%' : '°';
    document.getElementById('slider-val-' + activeSlider).textContent = Math.round(state[activeSlider]) + valSuffix;

    updateVisuals();
}

function updateVisuals() {
    // --- 1. Calculate Lift ---
    // Lift is proportional to RPM squared and Pitch
    const rpmFactor = state.rpm / 100;
    const pitchFactor = state.pitch / 20;

    // Stall penalty if pitch is extremely high and RPM is extremely low (Simplified)
    let liftAmount = rpmFactor * rpmFactor * pitchFactor; 

    // Update Metrics Panel
    document.getElementById('metric-wind').textContent = Math.round(state.rpm * 4) + ' mph';
    document.getElementById('metric-aoa').textContent = Math.round(state.pitch) + '°';

    let liftStr = "Minimal";
    let liftColor = "#475569";
    if (liftAmount > 0.8) { liftStr = "MAXIMUM"; liftColor = "#10b981"; }
    else if (liftAmount > 0.4) { liftStr = "High"; liftColor = "#3b82f6"; }
    else if (liftAmount > 0.1) { liftStr = "Moderate"; liftColor = "#8b5cf6"; }

    // Visual stall warning
    if (state.pitch > 16 && state.rpm < 40) {
        liftStr = "STALL RISK";
        liftColor = "#ef4444";
        liftAmount *= 0.5; // Lift drops in a stall
    }

    document.getElementById('metric-lift').textContent = liftStr;
    document.getElementById('metric-lift').setAttribute('fill', liftColor);

    // --- 2. Update Airfoil View ---
    // Rotate the airfoil based on pitch angle (rotate around center of pressure)
    const angle = state.pitch;
    document.getElementById('airfoil-model').setAttribute('transform', `rotate(${-angle})`);

    // Draw Angle of Attack Arc dynamically
    // Arc needs to go from (-100, 0) up to the rotated axis. 
    // Math: x = -100 * cos(a), y = -100 * sin(a)
    const rad = (angle * Math.PI) / 180;
    const arcX = -100 * Math.cos(rad);
    const arcY = -100 * Math.sin(rad);
    if (angle > 0) {
        document.getElementById('aoa-arc').setAttribute('d', `M -100,0 A 100 100 0 0 1 ${arcX},${arcY}`);
    } else {
        document.getElementById('aoa-arc').setAttribute('d', `M -100,0 L -100,0`); // Hide
    }

    // Scale Lift Vector
    const liftPixels = Math.max(10, liftAmount * 180);
    document.getElementById('vec-lift').setAttribute('y2', -liftPixels);
    document.getElementById('lbl-lift').setAttribute('y', -(liftPixels + 10));

    // Rotate the entire wind group slightly downwards (Downwash) based on lift
    const downwashAngle = liftAmount * 10;
    document.getElementById('wind-group').setAttribute('transform', `rotate(${downwashAngle})`);

    // --- 3. Update Spinning View Vectors ---
    // Velocity vectors scale directly with RPM (V = w * r)
    const vScale = Math.max(0.1, state.rpm / 100);
    document.getElementById('v1').setAttribute('y2', -10 - (30 * vScale));
    document.getElementById('v2').setAttribute('y2', -10 - (70 * vScale));
    document.getElementById('v3').setAttribute('y2', -10 - (120 * vScale));
}

// 60fps Animation Loop
function animationLoop(timestamp) {
    if (!lastTime) lastTime = timestamp;
    const dt = timestamp - lastTime || 16;
    lastTime = timestamp;

    // 1. Animate Wind Stream (Airfoil View)
    // Speed is based on RPM
    const windSpeed = (state.rpm * 0.15) + 1; // +1 so it moves slightly even at 0 rpm
    windOffset -= windSpeed;

    const windStreams = document.getElementsByClassName('wind-stream');
    for (let i = 0; i < windStreams.length; i++) {
        windStreams[i].setAttribute('stroke-dashoffset', windOffset);
    }

    // 2. Animate Rotor Spin (Top-Down View)
    const spinSpeed = (state.rpm * 0.3);
    spinAngle = (spinAngle + spinSpeed) % 360;
    document.getElementById('spin-system').setAttribute('transform', `rotate(${spinAngle})`);

    // Vector visibility in top-down view (only show vectors on the right side where advancing)
    // To make it look clean, we keep the vectors attached to the spin group but rotate them opposite so they always point "up" (forward).
    document.getElementById('vel-vectors').setAttribute('transform', `rotate(${-spinAngle})`);

    // Optional: Fade vectors out if they are on the retreating side, but for this simplified educational view, we'll keep them pointing strictly forward along the blade line as if frozen in a strobe light, which actually means we DON'T counter-rotate them.
    // Let's remove the counter-rotation so they spin with the blade to show exact local velocity direction!
    document.getElementById('vel-vectors').setAttribute('transform', `rotate(0)`);

    requestAnimationFrame(animationLoop);
}
